/**
 * 深抓 v5 — DOM + JS 数据提取方案
 *
 * 放弃 API 拦截（getChatMessageListExtra 只返回元数据），
 * 改为导航到对话页后从 DOM/JS 中提取消息。
 */
import { chromium } from 'playwright';
import { writeFileSync, mkdirSync, existsSync, readFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..', 'data');
const CDP_URL = 'http://127.0.0.1:9222';

if (!existsSync(DATA_DIR)) mkdirSync(DATA_DIR, { recursive: true });

function ts() {
  return new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
}

async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) throw new Error('未找到小满页面');
  const talkFrame = page.frames()[1];
  if (!talkFrame) throw new Error('未找到聊天 iframe');
  return { browser, page, talkFrame };
}

async function main() {
  console.log('[deep-scrape-api v5] 连接小满...');
  const { page, talkFrame } = await connect();

  // Step 1: 提取全量客户原始数据
  console.log('Step 1: 提取全量客户原始数据...');
  const allRaw = await talkFrame.evaluate(() => {
    const data = window.__conversationListFullData__;
    if (!data || !Array.isArray(data)) return [];
    return data
      .filter(item => {
        const name = item.contact?.name || '';
        return name && !/Assistant\s*Eva/i.test(name) && !/系统通知/.test(name) && name.length > 1;
      })
      .map(item => {
        const c = item.contact || {};
        return {
          name: c.name || item.name || '',
          accountId: c.accountId || item.accountId || '',
          accountIdEncrypt: c.accountIdEncrypt || item.accountIdEncrypt || '',
          chatToken: c.chatToken || item.chatToken || '',
          cid: item.cid || '',
          aliIdEncrypt: c.aliIdEncrypt || item.aliIdEncrypt || '',
          loginId: c.loginId || item.loginId || '',
        };
      });
  });
  console.log(`   ${allRaw.length} 个客户`);

  function findRaw(name) {
    let r = allRaw.find(r => r.name === name);
    if (r) return r;
    r = allRaw.find(r => r.name.includes(name) || name.includes(r.name));
    return r;
  }

  // Step 2: 读取 P0 客户列表
  console.log('Step 2: 读取 P0 客户列表...');
  const files = readdirSync(DATA_DIR).filter(f => f.includes('全量客户分类'));
  files.sort().reverse();
  const latest = files[0];
  if (!latest) { console.log('未找到分类数据'); return; }

  const classified = JSON.parse(readFileSync(join(DATA_DIR, latest), 'utf-8'));
  const p0Customers = classified.customers.filter(c => c.priority === 'P0');
  console.log(`   ${p0Customers.length} 个 P0 客户`);

  // =========================================================
  // Step 3: 逐个导航到对话页，从 DOM 提取消息
  // =========================================================
  console.log('Step 3: 逐个获取对话...');
  const results = [];
  let successCount = 0;

  for (let i = 0; i < p0Customers.length; i++) {
    const c = p0Customers[i];
    const raw = findRaw(c.name);

    if (!raw || !raw.accountIdEncrypt || !raw.chatToken) {
      console.log(`  [${i+1}/${p0Customers.length}] ${c.name} — 缺少加密ID，跳过`);
      results.push({ name: c.name, error: '缺少 accountIdEncrypt/chatToken', messages: [] });
      continue;
    }

    console.log(`  [${i+1}/${p0Customers.length}] ${c.name} (${c.countryCode})...`);

    try {
      const targetUrl = `https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman&activeAccountId=${raw.accountId}&activeAccountIdEncrypt=${encodeURIComponent(raw.accountIdEncrypt)}&chatToken=${encodeURIComponent(raw.chatToken)}&version=2.0.0`;

      await talkFrame.goto(targetUrl, { waitUntil: 'domcontentloaded', timeout: 15000 }).catch(() => {});

      // 等待消息区域加载
      await new Promise(r => setTimeout(r, 3000));

      // 尝试从 JS 变量提取消息
      const msgs = await talkFrame.evaluate(() => {
        // 尝试多个途径获取消息
        const sources = [];

        // 1. window.__chatMessages__ 或类似全局变量
        for (const key of Object.keys(window)) {
          if (/message/i.test(key) && !/list/i.test(key)) {
            const val = window[key];
            if (Array.isArray(val) && val.length > 0) {
              sources.push({ source: `window.${key}`, data: val });
            }
          }
        }

        // 2. DOM 提取 — 查找消息气泡
        const msgElements = document.querySelectorAll('[class*="message"], [class*="msg"], [class*="chat-item"], [class*="bubble"]');
        if (msgElements.length > 0) {
          const domMsgs = [];
          msgElements.forEach(el => {
            const text = el.textContent?.trim();
            if (text && text.length > 2) {
              domMsgs.push({ text: text.substring(0, 200), className: el.className });
            }
          });
          if (domMsgs.length > 0) sources.push({ source: 'DOM', data: domMsgs });
        }

        // 3. 尝试找 React/Vue 实例挂载的数据
        const appRoot = document.getElementById('app') || document.getElementById('root') || document.querySelector('[data-reactroot]');
        if (appRoot) sources.push({ source: 'appRoot.tag', data: appRoot.tagName });

        // 4. 列出所有包含 "message" 的 CSS 类名
        const allEls = document.querySelectorAll('*');
        const msgClasses = new Set();
        allEls.forEach(el => {
          if (el.className && typeof el.className === 'string') {
            el.className.split(/\s+/).forEach(cls => {
              if (/message|msg|chat|content|text/i.test(cls)) msgClasses.add(cls);
            });
          }
        });
        if (msgClasses.size > 0) sources.push({ source: 'classes_with_msg', data: [...msgClasses].slice(0, 50) });

        return sources;
      });

      // 首次对话保存详细探索结果
      if (i === 0) {
        writeFileSync(join(DATA_DIR, '_debug_dom_explore.json'), JSON.stringify({
          customer: c.name,
          url: targetUrl,
          talkFrameUrl: talkFrame.url(),
          sources: msgs,
        }, null, 2));
        console.log(`    [debug] DOM 探索结果已保存, ${msgs.length} 个数据源`);
        msgs.forEach(s => console.log(`    [debug]   ${s.source}: ${JSON.stringify(s.data).substring(0, 200)}`));
      }

      // 尝试从 DOM 提取实际对话消息
      const messages = await talkFrame.evaluate(() => {
        const result = [];

        // 尝试常见的消息列表选择器
        const selectors = [
          '.message-item', '.msg-item', '.chat-message', '.im-message',
          '[class*="messageItem"]', '[class*="msgItem"]',
          '.message-list > div', '.msg-list > div', '.chat-list > div',
          '[data-message-id]', '[data-msg-id]',
        ];

        for (const sel of selectors) {
          const items = document.querySelectorAll(sel);
          if (items.length > 0) {
            items.forEach(el => {
              const timeEl = el.querySelector('[class*="time"], [class*="date"], time, .timestamp');
              const text = el.textContent?.trim();
              if (text && text.length > 2) {
                result.push({
                  selector: sel,
                  time: timeEl?.textContent?.trim() || '',
                  text: text.substring(0, 500),
                });
              }
            });
            if (result.length > 0) break;
          }
        }

        return result;
      });

      results.push({
        name: c.name,
        accountId: raw.accountId,
        messageCount: messages.length,
        messages,
        exploreSources: i === 0 ? msgs.length : undefined,
      });
      if (messages.length > 0) successCount++;
      console.log(`    ${messages.length > 0 ? '✅' : '❌'} ${messages.length} 条消息${i === 0 ? ' (已保存探索数据)' : ''}`);

    } catch(e) {
      results.push({ name: c.name, error: e.message, messages: [] });
      console.log(`    ❌ ${e.message}`);
    }

    await new Promise(r => setTimeout(r, 2000));
  }

  // Step 4: 保存结果
  const output = {
    scrapedAt: new Date().toISOString(),
    method: 'dom-extraction-v5',
    totalTargeted: p0Customers.length,
    successCount,
    results,
  };

  const outFile = `deep_scrape_api_${ts()}.json`;
  writeFileSync(join(DATA_DIR, outFile), JSON.stringify(output, null, 2));
  console.log(`\n✅ 已保存: ${outFile} (${successCount}/${p0Customers.length} 成功)`);

  console.log('\n── 结果概览 ──');
  results.forEach(r => {
