      ? (r.messages[r.messages.length - 1]?.text || '').substring(0, 60)
      : (r.error || '无消息');
    console.log(`  ${icon} ${r.name}: ${r.messageCount}条 | 最后: "${preview}"`);
  });
}

main().catch(err => {
  console.error('[deep-scrape-api v5] 错误:', err.message);
  process.exit(1);
});

